import json
from openai import OpenAI

client = OpenAI()

# Agentic AI: same model, placed in a tool-calling loop
tools = [
    {
        "type": "function",
        "function": {
            "name": "fetch_url",
            "description": "Fetch the text content of a URL",
            "parameters": {
                "type": "object",
                "properties": {"url": {"type": "string", "format": "uri"}},
                "required": ["url"]
            }
        }
    }
]

def fetch_url(url: str) -> str:
    import urllib.request
    with urllib.request.urlopen(url, timeout=10) as resp:
        return resp.read().decode(errors="replace")[:3000]

messages = [
    {"role": "user", "content": "Fetch https://example.com and summarize what the page says."}
]

while True:
    response = client.chat.completions.create(
        model="gpt-4o-mini",
        messages=messages,
        tools=tools,
    )
    msg = response.choices[0].message
    messages.append(msg)

    if not msg.tool_calls:
        print(msg.content)  # final answer after seeing real page content
        break

    for call in msg.tool_calls:
        args = json.loads(call.function.arguments)
        result = fetch_url(args["url"])
        messages.append({"role": "tool", "tool_call_id": call.id, "content": result})

# The model ran twice: once to decide to call fetch_url, once to summarize its output.
# The architecture — not the model — made this agentic.

